#!/usr/bin/env python3
# Regenerate the wiki.test.ids.u32 tokens file for kaiju-ppl (KAIJU1_NATIVE_PPL.md).
#
#   python3 tokenize.py <tokenizer.json> <corpus.raw> <out.ids.u32>
#
# Uses the Qwen2.5 BPE tokenizer with add_special_tokens=False (no BOS, matching
# the qwen2.5 GGUF add_bos_token=false), and writes token ids as little-endian
# u32 — the exact format kaiju-ppl expects (<ids.u32le>).
#
# Reference slice: qwen2.5-tokenizer.json + wikitext-2-raw/wiki.test.raw
# (ggml-org CI zip) -> 299,078 tokens.
import sys, struct
from tokenizers import Tokenizer

if len(sys.argv) != 4:
    sys.exit("usage: tokenize.py <tokenizer.json> <corpus.raw> <out.ids.u32>")
tok_json, corpus, out = sys.argv[1], sys.argv[2], sys.argv[3]
tk = Tokenizer.from_file(tok_json)
with open(corpus, "r", encoding="utf-8") as f:
    text = f.read()
ids = tk.encode(text, add_special_tokens=False).ids
with open(out, "wb") as f:
    f.write(struct.pack("<%dI" % len(ids), *ids))
print(f"wrote {len(ids)} u32 tokens -> {out} ({len(ids)*4} bytes)")
